24 class Texture{
25     private:
26         GLuint textureID;
27         std::shared_ptr<Graphics::Image::Image> cpuImage;
28         int width, height;
29         bool ownsTexture = true;
30         std::string sourceAssetRef;
31     public:
32 
36         Texture() : textureID(0), width(0), height(0){};
37         ~Texture();
38         Texture(std::shared_ptr<Graphics::Image::Image> image, GLenum imageHint = GL_TEXTURE_2D);
39         Texture(const Texture&) = delete; // dont allow copying Texture tex = val.getTexture(); is invald Texture* tex = val.getTexturePtr() is okay tho.
40         Texture(int width, int height) : textureID(0), width(width), height(height) {};
41 
42         void bind(unsigned int slot = 0) const;
43         void unbind() const;
44         void dispose();
45 
46         inline int getWidth() {return this->width;}
47         inline int getHeight() {return this->height;}
48         GLuint& getID() {return this->textureID;}
49         const std::string& getSourceAssetRef() const { return sourceAssetRef; }
50         void setSourceAssetRef(const std::string& assetRef) { sourceAssetRef = assetRef; }
51 
52         std::shared_ptr<Graphics::Image::Image> getImageData() const {return cpuImage;}
53 
54         static std::shared_ptr<Texture> Load(PAsset asset, GLenum imageHint = GL_TEXTURE_2D, bool flipVertically = true);
55         static std::shared_ptr<Graphics::Image::Image> LoadImage(PAsset asset, bool flipVertically = true);
56         static std::shared_ptr<Texture> CreateEmpty(int width, int height);
57         static std::shared_ptr<Texture> CreateRenderTarget(
58             int width,
59             int height,
60             GLenum internalFormat = GL_RGBA16F,
61             GLenum format = GL_RGBA,
62             GLenum type = GL_FLOAT
63         );
64         static std::shared_ptr<Texture> CreateFromAlphaBuffer(int width, int height, const unsigned char* alphaData);
65         static std::shared_ptr<Texture> CreateFromExisting(GLuint id, int width, int height, bool owns = false);
66         static void FlushPendingDeletes();
67 
68         static void Unload(std::shared_ptr<Texture>& tex){
69             if(tex){
70                 tex->dispose();
71                 tex.reset();
72             }
73         }
74 
75         static void FlipVerticallyOnLoad(int i);
76 };
